uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    mat2 rot1 = {q5, q6,
                     -q6, q5};
    mat2 rot2 = {q7, q8,
                     -q8, q7};
    mat2 rot3 = {q9, q10,
                    -q10, q9};
    mat2 rot4 = {q11, q12,
                     -q12, q11};
    mat2 rot5 = {q13, q14,
                     -q14, q13};


    ret = texture(sampler_main, multiply((vUv-0.5),rot1) + 0.5)*0.2 +
          texture(sampler_main, multiply((vUv-0.5),rot2) + 0.5)*0.2 +
          texture(sampler_main, multiply((vUv-0.5),rot3) + 0.5)*0.2 +
          texture(sampler_main, multiply((vUv-0.5),rot4) + 0.5)*0.2 +
          texture(sampler_main, multiply((vUv-0.5),rot5) + 0.5)*0.2;

  //  vec2 uv_echo = (vUv - 0.5)*vec2(-1,1) + 0.5;
  //  ret = mix( texture(sampler_main, (vUv-0.5)*0.98 + 0.5).xyz,
  //              texture(sampler_main, (uv_echo-0.5)*0.98 + 0.5).xyz,
  //              0.50
  //            )  + GetBlur3(vUv) + GetBlur3(uv_echo)
  //            + GetBlur1(vUv) + GetBlur1(uv_echo); //video echo; //video ech//o
   // ret *= 10.00; //gamma
    //ret =  ret*(1 - ret)*10; //brighten
  ret = ret*lum(ret)*20;

  fragColor = ret;
}
